parameters.jsCode:
const claude = $input.first().json;
const noteData = $('Parse Note Content').first().json;

let categorization;
try {
  categorization = JSON.parse(claude.content[0].text);
} catch (e) {
  const match = claude.content[0].text.match(/\{[\s\S]*\}/);
  categorization = match ? JSON.parse(match[0]) : {
    para_category: 'Resources',
    subcategory: 'Uncategorized',
    tags: [],
    key_concepts: [],
    note_type: 'reference',
    confidence: 0
  };
}

const newFrontmatter = `---
created: ${new Date().toISOString()}
para: ${categorization.para_category}
subcategory: ${categorization.subcategory}
tags: [${categorization.tags.map(t => `#${t}`).join(', ')}]
key_concepts: [${categorization.key_concepts.join(', ')}]
note_type: ${categorization.note_type}
categorized_at: ${new Date().toISOString()}
confidence: ${categorization.confidence}
---`;

return [{
  json: {
    file_path: noteData.file_path,
    para_category: categorization.para_category,
    subcategory: categorization.subcategory,
    new_file_path: `/vault/${categorization.para_category}/${categorization.subcategory}/`,
    updated_content: newFrontmatter + '\n\n' + noteData.content,
    tags: categorization.tags,
    confidence: categorization.confidence,
    reasoning: categorization.reasoning
  }
}];
